scwin.f_AutoDivisition = async function () {
  if (ds_retrieve.getRowCount() < 1) {
    $c.win.alert($p, "조회먼저 하세요!");
    return;
  }
  if (ed_rotation.getValue() == "0" || ed_rotation.getValue() == "") {
    $c.win.alert($p, "회전수를 입력하세요!");
    return;
  }
  if ((ed_qty.getValue() == "0" || ed_qty.getValue() == "") & (ed_wt.getValue() == "0" || ed_wt.getValue() == "") & (ed_wt.getValue() == "0" || ed_wt.getValue() == "")) {
    $c.win.alert($p, "값을 입력해주세요!");
    return;
  }

  // 수량,중량,cbm 체크 - ed_qty, ed_wt, ed_cbm, ds_retrieve, remainQty
  if (Number(ed_qty.getValue()) > Number(ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "remainQty"))) {
    let confYn = await $c.win.confirm($p, "잔여수량보다 작업수량이 큽니다. 그래도 진행하시겠습니까?");
    if (!confYn) {
      return false;
    }
  }
  if (Number(ed_wt.getValue()) > Number(ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "remainWt"))) {
    let confYn = await $c.win.confirm($p, "잔여중량보다 작업중량이 큽니다. 그래도 진행하시겠습니까?");
    if (!confYn) {
      return false;
    }
  }
  if (Number(ed_cbm.getValue()) > Number(ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "remainCbm"))) {
    let confYn = await $c.win.confirm($p, "잔여CBM보다 작업CBM이 큽니다. 그래도 진행하시겠습니까?");
    if (!confYn) {
      return false;
    }
  }
  ds_scdretrieve.removeAll();
  var v_wrkStDtm = ica_inOutDt.getValue() + ed_inOutHh.getValue();
  var workStartDate = "";
  if (v_wrkStDtm.trim() > 0) {
    workStartDate = v_wrkStDtm;
  } else {
    workStartDate = scwin.sTodayTime;
  }
  var nextWorkEndDate = $c.date.getServerDateTime($p, "yyyyMMddHHmm");
  var nextWorkEndDate2 = $c.date.getServerDateTime($p, "yyyyMMddHHmm");
  var totQty = 0;
  var totWt = 0;
  var totCubic = 0;

  // 첫라인이 있는경우 자동분할시 첫라인에 차량번호가 존재하는경우 차량번호가 존재하지 않는 라인의 차량번호를 첫라인의 
  // 차량번호로 채운다.

  var gridCnt = ds_scdretrieve.getRowCount();
  var selfVehclNo; // 차량번호
  var copCoClntNm; // 협력업체
  var eqKndNm; // 적용규격
  var eqNrmNm; // 차종
  var eqCd; // 장비코드

  var startCnt = 0;
  for (var i = 0; i < ds_scdretrieve.getRowCount(); i++) {
    if (ds_scdretrieve.getRowStatus(i) == "C") {
      startCnt = i;
      break;
    }
  }
  if (startCnt > -1) {
    selfVehclNo = ds_scdretrieve.getCellData(startCnt, "selfVehclNo"); // 차량번호
    copCoClntNm = ds_scdretrieve.getCellData(startCnt, "copCoClntNm"); // 협력업체
    eqKndNm = ds_scdretrieve.getCellData(startCnt, "eqKndNm"); // 적용규격
    eqNrmNm = ds_scdretrieve.getCellData(startCnt, "eqNrmNm"); // 차종
    eqCd = ds_scdretrieve.getCellData(startCnt, "eqCd"); // 차종
  }
  var baseDate = workStartDate;
  var interval = Number(ed_interval.getValue());
  for (var i = 1; i <= ed_rotation.getValue(); i++) {
    // 회전수 만큼 Row Add
    var nextWorkEndDate = $c.date.addMinute($p, baseDate, i * interval);
    var nextWorkEndDate2 = $c.date.addMinute($p, baseDate, (i + 1) * interval);
    var iRow = ds_scdretrieve.insertRow();
    ds_scdretrieve.setCellData(iRow, "odrNo", ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "odrNo"));
    ds_scdretrieve.setCellData(iRow, "blNo", ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "blNo"));
    ds_scdretrieve.setCellData(iRow, "commCd", ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "commCd"));
    ds_scdretrieve.setCellData(iRow, "commNm", ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "commNm"));
    ds_scdretrieve.setCellData(iRow, "dptDt", nextWorkEndDate.substr(0, 8));
    ds_scdretrieve.setCellData(iRow, "dptHh", nextWorkEndDate.substr(8));
    ds_scdretrieve.setCellData(iRow, "arvDt", nextWorkEndDate2.substr(0, 8));
    ds_scdretrieve.setCellData(iRow, "arvHh", nextWorkEndDate2.substr(8));
    ds_scdretrieve.setCellData(iRow, "dptWrkPlCd", ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "dptWrkPlCd"));
    ds_scdretrieve.setCellData(iRow, "dptWrkPlNm", ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "dptWrkPlNm"));
    ds_scdretrieve.setCellData(iRow, "arvWrkPlCd", ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "arvWrkPlCd"));
    ds_scdretrieve.setCellData(iRow, "arvWrkPlNm", ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "arvWrkPlNm"));
    ds_scdretrieve.setCellData(iRow, "odrKndCd", ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "odrKndCd"));
    ds_scdretrieve.setCellData(iRow, "intCommSeq", ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "commSeq"));
    ds_scdretrieve.setCellData(iRow, "bilgClntNo", ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "bilgClntNo"));
    ds_scdretrieve.setCellData(iRow, "odrWrkPathSeq", ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "odrWrkPathSeq"));
    ds_scdretrieve.setCellData(iRow, "odrWrkStpSeq", ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "odrWrkStpSeq"));
    ds_scdretrieve.setCellData(iRow, "clntMgntNo", ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "clntMgntNo"));
    if (i == ed_rotation.getValue()) {
      ds_scdretrieve.setCellData(iRow, "wrkQty", Number(ed_qty.getValue()) - Number(totQty));
      ds_scdretrieve.setCellData(iRow, "wrkWt", Number(ed_wt.getValue()) - Number(totWt));
      ds_scdretrieve.setCellData(iRow, "wrkCubic", Number(ed_cbm.getValue()) - Number(totCubic));
      ed_rotation.setValue(0);
      ed_interval.setValue(0);
      ed_wt.setValue(0);
      ed_qty.setValue(0);
      ed_cbm.setValue(0);
    } else {
      ds_scdretrieve.setCellData(iRow, "wrkQty", Math.round(Number(ed_qty.getValue()) / Number(ed_rotation.getValue())));
      ds_scdretrieve.setCellData(iRow, "wrkWt", Math.round(Number(ed_wt.getValue()) / Number(ed_rotation.getValue())));
      ds_scdretrieve.setCellData(iRow, "wrkCubic", Math.round(Number(ed_cbm.getValue()) / Number(ed_rotation.getValue())));
      totQty += ds_scdretrieve.getCellAllData(iRow, "wrkQty");
      totWt += ds_scdretrieve.getCellAllData(iRow, "wrkWt");
      totCubic += ds_scdretrieve.getCellAllData(iRow, "wrkCubic");
    }
  }
  if (gridCnt < 1) {
    return;
  }
  for (var i = startCnt; i < ds_scdretrieve.getRowCount(); i++) {
    if (ds_scdretrieve.getCellData(i, 'vehclShortCd') == "") {
      //단축코드
      ds_scdretrieve.setCellData(i, 'vehclShortCd', ds_scdretrieve.getCellData(startCnt, 'vehclShortCd'));
    }
    if (ds_scdretrieve.getCellData(i, 'selfVehclNo') == "") {
      ds_scdretrieve.setCellData(i, 'selfVehclNo', ds_scdretrieve.getCellData(startCnt, 'selfVehclNo'));
    }
    if (ds_scdretrieve.getCellData(i, 'copCoClntNo') == "") {
      ds_scdretrieve.setCellData(i, 'copCoClntNo', ds_scdretrieve.getCellData(startCnt, 'copCoClntNo'));
    }
    if (ds_scdretrieve.getCellData(i, 'copCoClntNm') == "") {
      ds_scdretrieve.setCellData(i, 'copCoClntNm', ds_scdretrieve.getCellData(startCnt, 'copCoClntNm'));
    }
    if (ds_scdretrieve.getCellData(i, 'eqKndCd') == "") {
      ds_scdretrieve.setCellData(i, 'eqKndCd', ds_scdretrieve.getCellData(startCnt, 'eqKndCd'));
    }
    if (ds_scdretrieve.getCellData(i, 'eqKndNm') == "") {
      ds_scdretrieve.setCellData(i, 'eqKndNm', ds_scdretrieve.getCellData(startCnt, 'eqKndNm'));
    }
    if (ds_scdretrieve.getCellData(i, 'eqNrmCd') == "") {
      ds_scdretrieve.setCellData(i, 'eqNrmCd', ds_scdretrieve.getCellData(startCnt, 'eqNrmCd'));
    }
    if (ds_scdretrieve.getCellData(i, 'eqNrmNm') == "") {
      ds_scdretrieve.setCellData(i, 'eqNrmNm', ds_scdretrieve.getCellData(startCnt, 'eqNrmNm'));
    }
    if (ds_scdretrieve.getCellData(i, 'eqCd') == "") {
      ds_scdretrieve.setCellData(i, 'eqCd', ds_scdretrieve.getCellData(startCnt, 'eqCd'));
    }
    if (ds_scdretrieve.getCellData(i, 'bilgClntNo') == "") {
      ds_scdretrieve.setCellData(i, 'bilgClntNo', ds_scdretrieve.getCellData(startCnt, 'bilgClntNo'));
    }
    if (ds_scdretrieve.getCellData(i, 'odrKndCd') == "") {
      ds_scdretrieve.setCellData(i, 'odrKndCd', ds_scdretrieve.getCellData(startCnt, 'odrKndCd'));
    }
    if (ds_scdretrieve.getCellData(i, 'clntMgntNo') == "") {
      ds_scdretrieve.setCellData(i, 'clntMgntNo', ds_scdretrieve.getCellData(startCnt, 'clntMgntNo'));
    }
    if (ds_scdretrieve.getCellData(i, 'intCommSeq') == "") {
      ds_scdretrieve.setCellData(i, 'intCommSeq', ds_scdretrieve.getCellData(startCnt, 'commSeq'));
    }
    if (ds_scdretrieve.getCellData(i, 'odrWrkPathSeq') == "") {
      ds_scdretrieve.setCellData(i, 'odrWrkPathSeq', ds_scdretrieve.getCellData(startCnt, 'odrWrkPathSeq'));
    }
    if (ds_scdretrieve.getCellData(i, 'odrWrkStpSeq') == "") {
      ds_scdretrieve.setCellData(i, 'odrWrkStpSeq', ds_scdretrieve.getCellData(startCnt, 'odrWrkStpSeq'));
    }
  }
};

