scwin.f_Save = async function () {
  var chk = 0;
  if (scwin.f_prefareCheck() == false) return;
  for (var i = 0; i < ds_retrieve.getRowCount(); i++) {
    if (ds_retrieve.getCellData(i, "chk") == "T") chk++;
  }
  if (chk > 1) {
    $c.win.alert($p, "한개 이상의 오더를 선택하셨습니다!");
    return false;
  } else if (chk == 0) {
    $c.win.alert($p, "하나의 오더를 선택해야 합니다!");
    return false;
  } else if (ds_scdretrieve.getModifiedIndex().length == 0 && ds_scdretrieve.getRowPosition() == -1) {
    $c.win.alert($p, "조회된 데이타가 없습니다.");
    return false;
  } else if (ds_scdretrieve.getModifiedIndex().length == 0) {
    await $c.gus.cfAlertMsg($p, MSG_CM_WRN_001, ["Data"]);
    return false;
  }

  // 수량,중량,cbm 체크 - ed_qty, ed_wt, ed_cbm, ds_retrieve, remainQty, ds_scdretrieve
  var newMadeSumQty = 0;
  var newMadeSumWt = 0;
  var newMadeSumQubic = 0;
  var strOdrNoCnt = 0;
  for (var i = 0; i < ds_scdretrieve.getRowCount(); i++) {
    if (ds_scdretrieve.getRowStatus(i) == "C") {
      newMadeSumQty += Number(ds_scdretrieve.getCellAllData(i, "wrkQty"));
      newMadeSumWt += Number(ds_scdretrieve.getCellAllData(i, "wrkWt"));
      newMadeSumQubic += Number(ds_scdretrieve.getCellAllData(i, "wrkQubic"));
      if (ds_scdretrieve.getCellAllData(i, "strOdrNo") == "") {
        strOdrNoCnt++;
      }
    }
  }
  if (newMadeSumQty > ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "remainQty")) {
    if ($c.win.confirm($p, "잔여수량보다 입고처리수량이 큽니다. 그래도 진행하시겠습니까?") == false) return false;
  }
  if (newMadeSumWt > ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "remainWt")) {
    if ($c.win.confirm($p, "잔여중량보다 입고처리중량이 큽니다. 그래도 진행하시겠습니까?") == false) return false;
  }
  if (newMadeSumQubic > ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "remainCbm")) {
    if ($c.win.confirm($p, "잔여CBM보다 입고처리CBM이 큽니다. 그래도 진행하시겠습니까?") == false) return false;
  }
  if (ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "rltNo") == "" || ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "rltNo") == null) {
    if ($c.win.confirm($p, "본선완료작업을 하지 않으셨습니다. B/L물량으로 처리하시겠습니까?") == false) return false;
  }
  if (strOdrNoCnt > 0) {
    if ($c.win.confirm($p, "보관오더를 선택하지 않았습니다. 그래도 진행하시겠습니까?") == false) return false;
  }
  let e = await $c.sbm.execute($p, sbm_regist);
  if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
    scwin.sbm_regist_submitdone(e);
  }
};
