scwin.f_shuttlehistory = function () {
  if (ds_scdretrieve.getRowCount() < 1) {
    $c.win.alert($p, "입고처리(출고처리) 데이터가 없습니다!");
    return;
  }
  var row = ds_scdretrieve.getRowPosition();
  var args = new Array();
  args[0] = ds_scdretrieve.NameValue(row, "invoiceNo"); //송장번호

  var row = ds_retrieve.getRowPosition();
  var param = {};
  param.odrNo = ds_retrieve.getCellData(row, "odrNo");
  param.mrn = ds_retrieve.getCellData(row, "mrn");
  param.msn = ds_retrieve.getCellData(row, "msn");
  param.hsn = ds_retrieve.getCellData(row, "hsn");
  param.blNo = ds_retrieve.getCellData(row, "blNo");
  param.wrkPlCd = ds_retrieve.getCellData(row, "pierYardWrkPlCd");
  param.wrkPlNm = "";
  param.cntrBulk = "B";
  param.openFlag = "1";
  var opts = {
    id: "POPUPWIN",
    popupName: "셔틀전송 History 조회",
    modal: true,
    type: "browserPopup",
    width: 1000,
    height: 460,
    title: "셔틀전송 History 조회"
  };
  $c.win.openPopup($p, "/ui/mt/al/wrkindict/mt_201_01_10p.xml", opts, param);
};
scwin.f_DeleteRow = function () {
  ds_scdretrieve.removeRow(ds_scdretrieve.getRowPosition());
};
scwin.f_Cancel = function () {
  $c.data.undoRow($p, ds_scdretrieve, "Y");
};
scwin.f_prefareCheck = function () {
  var startCnt = -1;
  for (var i = 0; i < ds_scdretrieve.getRowCount(); i++) {
    if (ds_scdretrieve.getRowStatus(i) == "C") {
      startCnt = i;
      break;
    }
  }
  for (var i = startCnt + 1; i < ds_scdretrieve.getRowCount(); i++) {
    if (ds_scdretrieve.getCellData(i, 'vehclShortCd') == "") {
      //단축코드
      ds_scdretrieve.setCellData(i, 'vehclShortCd', ds_scdretrieve.getCellData(i - 1, 'vehclShortCd'));
    }
    if (ds_scdretrieve.getCellData(i, 'coshippingPatternCd') == "") {
      //합적유형
      ds_scdretrieve.setCellData(i, 'coshippingPatternCd', ds_scdretrieve.getCellData(i - 1, 'coshippingPatternCd'));
    }
    if (ds_scdretrieve.getCellData(i, 'unitCd') == "") {
      //하불단위
      ds_scdretrieve.setCellData(i, 'unitCd', ds_scdretrieve.getCellData(i - 1, 'unitCd'));
    }
    if (ds_scdretrieve.getCellData(i, 'selfVehclNo') == "") {
      //차량번호
      ds_scdretrieve.setCellData(i, 'selfVehclNo', ds_scdretrieve.getCellData(i - 1, 'selfVehclNo'));
      if (ds_scdretrieve.getCellData(i, 'copCoClntNo') == "") {
        //협력업체
        ds_scdretrieve.setCellData(i, 'copCoClntNo', ds_scdretrieve.getCellData(i - 1, 'copCoClntNo'));
      }
      if (ds_scdretrieve.getCellData(i, 'copCoClntNm') == "") {
        //협력업체명
        ds_scdretrieve.setCellData(i, 'copCoClntNm', ds_scdretrieve.getCellData(i - 1, 'copCoClntNm'));
      }
    }
    if (ds_scdretrieve.getCellData(i, 'selfVehclNm') == "") {
      //차량번호명
      ds_scdretrieve.setCellData(i, 'selfVehclNm', ds_scdretrieve.getCellData(i - 1, 'selfVehclNm'));
    }
    if (ds_scdretrieve.getCellData(i, 'eqNrmCd') == "") {
      //차종
      ds_scdretrieve.setCellData(i, 'eqNrmCd', ds_scdretrieve.getCellData(i - 1, 'eqNrmCd'));
    }
    if (ds_scdretrieve.getCellData(i, 'eqNrmNm') == "") {
      //차종명
      ds_scdretrieve.setCellData(i, 'eqNrmNm', ds_scdretrieve.getCellData(i - 1, 'eqNrmNm'));
    }
    if (ds_scdretrieve.getCellData(i, 'eqKndCd') == "") {
      //적용규격
      ds_scdretrieve.setCellData(i, 'eqKndCd', ds_scdretrieve.getCellData(i - 1, 'eqKndCd'));
    }
    if (ds_scdretrieve.getCellData(i, 'eqKndNm') == "") {
      //적용규격명
      ds_scdretrieve.setCellData(i, 'eqKndNm', ds_scdretrieve.getCellData(i - 1, 'eqKndNm'));
    }
    if (ds_scdretrieve.getCellData(i, 'eqCd') == "") {
      //적용규격명
      ds_scdretrieve.setCellData(i, 'eqCd', ds_scdretrieve.getCellData(i - 1, 'eqCd'));
    }
    if (ds_scdretrieve.getCellData(i, 'etcTrfAdptClsCd') == "") {
      //기타 요율 적용
      ds_scdretrieve.setCellData(i, 'etcTrfAdptClsCd', ds_scdretrieve.getCellData(i - 1, 'etcTrfAdptClsCd'));
    }
  }
  for (var i = 0; i < ds_scdretrieve.getRowCount(); i++) {
    if (ds_scdretrieve.getRowStatus(i) == "C") {
      if (rd_inQryCond.getValue() == "C") {
        if (ds_scdretrieve.getCellData(i, 'coshippingPatternCd') == "") {
          //합적유형
          $c.win.alert($p, "합적유형을 입력하세요!");
          return false;
        }
        if (ds_scdretrieve.getCellData(i, 'unitCd') == "") {
          //하불단위
          $c.win.alert($p, "하불단위를 입력하세요!");
          return false;
        }
      }
      if (ds_scdretrieve.getCellData(i, 'selfVehclNo') == "") {
        //차량번호
        $c.win.alert($p, "차량번호를 입력하세요!");
        return false;
      }
      if (ds_scdretrieve.getCellData(i, 'eqNrmCd') == "") {
        //차종
        $c.win.alert($p, "차종을 입력하세요!");
        return false;
      }
      if (ds_scdretrieve.getCellData(i, 'eqKndCd') == "") {
        //적용규격
        $c.win.alert($p, "적용규격을 입력하세요!");
        return false;
      }
      if (ds_scdretrieve.getCellData(i, "unitCd") == "VHR" || ds_scdretrieve.getCellData(i, "unitCd") == "H/R") {
        //시간당 요율인 경우 시간을 입력해야 함
        if (ds_scdretrieve.getCellData(i, "tpchsAdptHhCd") == "") {
          $c.win.alert($p, "적용시간을 입력하세요!");
          return false;
        }
      }
    }
  }
};

