// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {
  // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
  if (!$c.gus.cfCanOpenPopup($p, inObj, pairObj)) return;

  // 짝이 되는 오브젝트의 값 제거
  $c.gus.cfClearPairObj($p, pairObj);

  // 검색어 세팅
  var pVal = $c.gus.cfGetValue($p, inObj);
  if (isCode == null || isCode == true) {
    // inObj가 코드 필드일 경우 팝업
    scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
  } else {
    // inObj가 코드명 필드일 경우 팝업
    scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
  }
};

// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
scwin.f_openCommonPopUp = async function (disGubun, pCode, pName, pClose, pAllSearch) {
  // 선언부
  var rtnList; // 공통POP-UP -> 요청화면 

  switch (disGubun) {
    case 1:
      // 작업장  팝업			
      udc_wrkPlCd.setSelectId("retrieveWrkPlInfo");
      rtnList = await udc_wrkPlCd.cfCommonPopUpAsync('', pCode, pName, pClose, null, null, null, null, null, "300", "400", null, null, null, pAllSearch, "작업장,작업장코드,작업장명");

      // 수요가코드  수요가명
      if (rtnList != null) {
        em_wrkPlCd.setValue(rtnList[0]);
        ed_wrkPlNm.setValue(rtnList[1]);
      } else {
        em_wrkPlCd.setValue("");
        ed_wrkPlNm.setValue("");
      }
      break;
    case 2:
      udc_comCode1.setSelectId("retrieveWrkPlInfo"); // XML상의 SELECT ID
      rtnList = await udc_comCode1.cfCommonPopUpAsync('' // 콜백 함수
      , pCode // 화면에서의 ??? Code Element의 Value
      , pName // 화면에서의 ??? Name Element의 Value
      , pClose // 결과가 1건 일때 원도우를 AutoClose 여부 (T:Close,F:Opened)
      , null // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
      , null // Title순서
      , null // 보여주는 각 컬럼들의 폭
      , null // 컬럼중에서 숨기는 컬럼 지정
      , null // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
      , null // POP-UP뛰을때 원도우의 사용자 정의 폭
      , null // POP-UP뛰을때 우도우의 사용자 정의 높이
      , null // 윈도우 위치 Y좌표
      , null // 윈도우 위치 X좌표
      , null // 중복체크여부 ("F")
      , pAllSearch // 전체검색허용여부 ("F")
      , "작업장,작업장코드,작업장명" // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번?검색Nm")
      );

      // 수요가코드  수요가명
      if (rtnList != null) {
        // return value Assign
        ds_scdretrieve.setCellData(ds_scdretrieve.getRowPosition(), "arvWrkPlCd", rtnList[0]); // 작업장코드
        ds_scdretrieve.setCellData(ds_scdretrieve.getRowPosition(), "arvWrkPlNm", rtnList[1]); // 작업장명

        if (ds_scdretrieve.getCellData(ds_scdretrieve.getRowPosition(), "arvWrkPlCd") == 'undefined') {
          ds_scdretrieve.setCellData(ds_scdretrieve.getRowPosition(), "arvWrkPlNm", '');
        }
      }
      break;
  }
};

