// 동부메탈 실적 및 완료 전송
scwin.f_metalCmpltSnd = async function () {
  if (ds_scdretrieve.getRowCount() == 0) {
    $c.win.alert($p, "배차된 차량이 없습니다. 배차 후에 진행하십시오.");
    return false;
  }
  if (ds_scdretrieve.getRowPosition() != 0) {
    $c.win.alert($p, "메탈 셔틀의 완료 및 실적처리는 첫번째 배차한 차량에만 사용 가능합니다.");
    return false;
  }
  if (chb_cmpltCheck.getValue()) {
    ds_scdretrieve.setCellData(0, "wrkWt", ed_metalVol.getValue());
    ds_scdretrieve.setCellData(0, "metalSndYn", 1);
  } else {
    if (ed_metalVol.value == 0) {
      $c.win.alert($p, "실적 물량이 0입니다. 확인 후 진행해 주십시오");
      ed_metalVol.focus();
      return false;
    }
    ds_scdretrieve.setCellData(0, "metalSndYn", 0);
    ds_scdretrieve.setCellData(0, "wrkWt", ed_metalVol.getValue());
  }
  let e = await $c.sbm.execute($p, sbm_registForMetal);
  if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
    scwin.sbm_registForMetal_submitdone(e);
  }
};
scwin.f_metalTransSnd = async function () {
  if (ds_scdretrieve.getRowCount() == 0) {
    $c.win.alert($p, "배차된 차량이 없습니다.  배차 후에 진행하십시오.");
    return false;
  }
  if (ds_scdretrieve.getCellData(ds_scdretrieve.getRowPosition(), "clntMgntNo") == "") {
    $c.win.alert($p, "동부메탈 오더번호가 없습니다. 벌크오더등록 화면의 Ref번호 란에 넣어주세요.");
    return false;
  }
  if (ed_metalTransCnt.getValue() < 1 || ed_metalTransCnt.getValue() > 99) {
    $c.win.alert($p, "추가 작업지시 횟수는 1부터 99까지 입력가능합니다.");
    ed_metalTransCnt.setValue(0);
    ed_metalTransCnt.focus();
    return false;
  }
  ds_scdretrieve.getCellData(ds_scdretrieve.getRowPosition(), "metalTransCnt", ed_metalTransCnt.getValue());
  let e = await $c.sbm.execute($p, sbm_metalTransAdd);
  if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
    scwin.sbm_metalTransAdd_submitdone(e);
  }
};
scwin.f_setBLVol = function () {
  if (chb_cmpltCheck.getValue()) {
    ed_metalVol.setValue(Number(ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "grossWt") / 1000));
    ed_metalVol.setReadOnly(true);
  } else {
    ed_metalVol.setValue(0);
    ed_metalVol.setReadOnly(false);
  }
};

