//-------------------------------------------------------------------------
scwin.ds_unitCd_ondataload = function () {
  if (ds_unitCd.getRowCount() == 0) {
    if (scwin.flagUnitCd == 0) {
      scwin.f_ComboWrkUnitCd(ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "ctrtNo"));
      scwin.flagUnitCd = 1;
      var rowIndex = ds_unitCd.insertRow();
      ds_unitCd.setRowPosition(rowIndex);
      ds_unitCd.setCellData(ds_unitCd.getRowPosition(), "Code", "TON");
      return;
    }
  }
  if (ds_scdretrieve.getCellData(ds_scdretrieve.getRowPosition(), "unitCd") == "") {
    ds_scdretrieve.setCellData(ds_scdretrieve.getRowPosition(), "unitCd", ds_unitCd.getCellData(0, "Code"));
  }
  scwin.flagUnitCd = 0;
};
scwin.ds_coshippingPatternCd_ondataload = function () {
  var rowCountBefore = ds_coshippingPatternCd.getRowCount();
  var rowIndex = ds_coshippingPatternCd.insertRow();
  ds_coshippingPatternCd.setRowPosition(rowIndex);
  ds_coshippingPatternCd.setCellData(ds_coshippingPatternCd.getRowPosition(), "Code", "D01");
  ds_scdretrieve.setCellData(ds_scdretrieve.getRowPosition(), "coshippingPatternCd", "D01");
  if (rowCountBefore == 0) {
    var rowIndex2 = ds_coshippingPatternCd.insertRow();
    ds_coshippingPatternCd.setRowPosition(rowIndex2);
    ds_coshippingPatternCd.setCellData(rowIndex2, "Code", DsConstants.COSHIPPING_PATTERN_CD_GROSS_WT);
    ds_scdretrieve.setCellData(ds_scdretrieve.getRowPosition(), "coshippingPatternCd", DsConstants.COSHIPPING_PATTERN_CD_GROSS_WT);
    return;
  }
  if (ds_scdretrieve.getCellData(ds_scdretrieve.getRowPosition(), "coshippingPatternCd") == "") {
    ds_scdretrieve.setCellData(ds_scdretrieve.getRowPosition(), "coshippingPatternCd", ds_coshippingPatternCd.getCellData(0, "CODE"));
  }
  scwin.f_ComboUnitCd(ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "bilgClntNo") // 청구거래처번호
  , ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "dptWrkPlCd") // 출발지
  , ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "wrkStDt") // 출발예정시간
  , ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "ctrtNo") // 계약번호
  , ds_scdretrieve.getCellData(ds_scdretrieve.getRowPosition(), "coshippingPatternCd"), "999");
};

